1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	interface Item {
12	  type: string;
13	  cursed?: boolean;
14	  enchantment?: number;
15	}
16	
17	const CURSE_RATE = 0.5;
18	const HIGH_ENCHANTMENT_THRESHOLD = 5;
19	const HIGH_ENCHANTMENT_RATE = 0.3;
20	const LOYALTY_THRESHOLD = 2;
21	const LOYALTY_RATE = 0.2;
22	
23	interface QuoteStep {
24	  op: "quote";
25	  items: Item[];
26	}
27	
28	interface Damage {
29	  itemType: string;
30	  amount: number;
31	}
32	
33	interface ClaimStep {
34	  op: "claim";
35	  policy: number;
36	  incident: { cause: string; damages: Damage[] };
37	}
38	
39	type Step = QuoteStep | ClaimStep;
40	
41	interface Customer {
42	  yearsWithMHPCO: number;
43	}
44	
45	interface Scenario {
46	  customer: Customer;
47	  steps: Step[];
48	}
49	
50	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
51	const COMPONENT_BASE = 25;
52	const BLOCK_SIZE = 3;
53	const BLOCK_BASE = 60;
54	
55	const componentBase = (count: number): number =>
56	  count === BLOCK_SIZE ? BLOCK_BASE : count * COMPONENT_BASE;
57	
58	const lookupByType = (
59	  type: string,
60	  componentValue: number,
61	  mainItemValues: Record<string, number>,
62	): number =>
63	  COMPONENT_TYPES.has(type) ? componentValue : (mainItemValues[type] ?? 0);
64	
65	const unitBase = (type: string): number =>
66	  lookupByType(type, COMPONENT_BASE, BASE_PREMIUMS);
67	
68	const baseForType = (type: string, count: number): number =>
69	  COMPONENT_TYPES.has(type)
70	    ? componentBase(count)
71	    : unitBase(type) * count;
72	
73	const countBy = <T>(values: T[], key: (value: T) => string): Map<string, number> =>
74	  values.reduce(
75	    (counts, value) =>
76	      counts.set(key(value), (counts.get(key(value)) ?? 0) + 1),
77	    new Map<string, number>(),
78	  );
79	
80	const countByType = (items: Item[]): Map<string, number> =>
81	  countBy(items, (item) => item.type);
82	
83	const baseForItems = (items: Item[]): number =>
84	  [...countByType(items)].reduce(
85	    (total, [type, count]) => total + baseForType(type, count),
86	    0,
87	  );
88	
89	const enchantmentLevel = (item: Item | undefined): number =>
90	  item?.enchantment ?? 0;
91	
92	const isHighlyEnchanted = (item: Item): boolean =>
93	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
94	
95	const surchargeRate = (item: Item): number =>
96	  (item.cursed ? CURSE_RATE : 0) +
97	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
98	
99	const itemSurcharges = (item: Item): number =>
100	  unitBase(item.type) * surchargeRate(item);
101	
102	const surchargesForItems = (items: Item[]): number =>
103	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
104	
105	const firstInsuranceSurcharge = (policyBase: number): number =>
106	  policyBase * FIRST_INSURANCE_RATE;
107	
108	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
109	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD ? policyBase * LOYALTY_RATE : 0;
110	
111	const isKnownType = (type: string): boolean =>
112	  COMPONENT_TYPES.has(type) || type in BASE_PREMIUMS;
113	
114	const validateKnownTypes = (items: Item[]): void => {
115	  for (const item of items) {
116	    if (!isKnownType(item.type)) {
117	      throw new Error(`Unknown item type: ${item.type}`);
118	    }
119	  }
120	};
121	
122	const priceQuote = (items: Item[], customer: Customer): { premium: number } => {
123	  validateKnownTypes(items);
124	  const policyBase = baseForItems(items);
125	  const surcharges = surchargesForItems(items);
126	  const premium = Math.ceil(
127	    policyBase +
128	      surcharges +
129	      firstInsuranceSurcharge(policyBase) -
130	      loyaltyDiscount(policyBase, customer) +
131	      PROCESSING_FEE,
132	  );
133	  return { premium };
134	};
135	
136	const DEDUCTIBLE = 100;
137	const CAP_MULTIPLIER = 2;
138	const HIGH_ENCHANTMENT_REIMBURSE_THRESHOLD = 8;
139	const REIMBURSE_RATE = 0.5;
140	
141	const INSURANCE_VALUES: Record<string, number> = {
142	  sword: 1000,
143	  amulet: 600,
144	  staff: 800,
145	  potion: 400,
146	};
147	const COMPONENT_INSURANCE_VALUE = 250;
148	
149	const insuranceValue = (type: string): number =>
150	  lookupByType(type, COMPONENT_INSURANCE_VALUE, INSURANCE_VALUES);
151	
152	const insuranceSum = (items: Item[]): number =>
153	  items.reduce((sum, item) => sum + insuranceValue(item.type), 0);
154	
155	const hasReducedReimbursement = (item: Item | undefined): boolean =>
156	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_REIMBURSE_THRESHOLD;
157	
158	const reimbursableAmount = (damage: Damage, item: Item | undefined): number =>
159	  hasReducedReimbursement(item)
160	    ? damage.amount * REIMBURSE_RATE
161	    : damage.amount;
162	
163	const damagePayout = (damage: Damage, items: Item[]): number => {
164	  const item = items.find((candidate) => candidate.type === damage.itemType);
165	  return Math.max(0, reimbursableAmount(damage, item) - DEDUCTIBLE);
166	};
167	
168	const initialCap = (items: Item[]): number =>
169	  insuranceSum(items) * CAP_MULTIPLIER;
170	
171	const desiredPayout = (damages: Damage[], items: Item[]): number =>
172	  damages.reduce((sum, damage) => sum + damagePayout(damage, items), 0);
173	
174	const validateDamageCounts = (damages: Damage[], items: Item[]): void => {
175	  const insuredCounts = countByType(items);
176	  const damageCounts = countBy(damages, (damage) => damage.itemType);
177	  for (const [itemType, damaged] of damageCounts) {
178	    if (damaged > (insuredCounts.get(itemType) ?? 0)) {
179	      throw new Error(
180	        `Claim rejected: more "${itemType}" damages than insured items`,
181	      );
182	    }
183	  }
184	};
185	
186	const processClaim = (
187	  step: ClaimStep,
188	  steps: Step[],
189	  remainingCapByPolicy: Map<number, number>,
190	): { payout: number; remainingCap: number } => {
191	  const policyStep = steps[step.policy] as QuoteStep;
192	  validateDamageCounts(step.incident.damages, policyStep.items);
193	  const remaining =
194	    remainingCapByPolicy.get(step.policy) ?? initialCap(policyStep.items);
195	  const desired = desiredPayout(step.incident.damages, policyStep.items);
196	  const payout = Math.floor(Math.min(desired, remaining));
197	  const remainingCap = remaining - payout;
198	  remainingCapByPolicy.set(step.policy, remainingCap);
199	  return { payout, remainingCap };
200	};
201	
202	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
203	  const remainingCapByPolicy = new Map<number, number>();
204	  const results = scenario.steps.map((step) =>
205	    step.op === "quote"
206	      ? priceQuote(step.items, scenario.customer)
207	      : processClaim(step, scenario.steps, remainingCapByPolicy),
208	  );
209	  return { results };
210	};
